const Q_PHYSICS_2015=[{"id": "objective>Physics>2015>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A satellite moves in a circular orbit of radius 4R round the earth. The acceleration of the satellite in terms of g is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4/g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">g/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">g/16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16/g</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The acceleration of the satelite  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">gR<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div>  <br/>  Where R and r are the radii of the orbit and the earth  <br/>  given: r = 4R;  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">gR<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(4R)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div>  <br/>   <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">gR<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />16R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div>  <br/> a = g/16</div>", "topic": "GRAVITATIONAL FIELD : PARKING ORBIT AND WEIGHTLESSNESS"}, {"id": "objective>Physics>2015>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the diagram below, the direction of the force between N and S in the magnetic field is  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SN</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">PM</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The direction between N and S in the magnetic field is NS</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2015>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the inductance of a coil of resistance 30Ω connected to a 100V, <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">50</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">π</span>Hz a.c source if the coil draws an r.m.s current of 2A</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.25H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.60H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4H</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>  Resistance, R = 30Ω  <br/>  Voltage, V = 100v  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Frequency,</td><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50<hr size=\"1\" />π</td><td style=\"text-align:center;\">Hz</td></tr></table></div> <br/>  I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r.m.s</span> = 2A  <br/>  Recall that  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2πfL</td></tr></table></div>  <br/>   Where X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> is the inductive reactance, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>, maximum voltage, f, frquency and I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> maximum/peak current.  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td><td style=\"text-align:center;\">;</td></tr></table></div>  <br/> X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 2πfL  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td></tr></table></div>  <br/>  Recall that:  <br/>  I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> = I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r.m.s</span>&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span>  <br/>  ∴ I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> = 2&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span>;  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />2&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span></td></tr></table></div>  <br/>  X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 2πfL ;  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">50<hr size=\"1\" />π</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">L</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">25&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">50<hr size=\"1\" />π</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">L</td></tr></table></div>  <br/>  L = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span>/4 ≈ = 0.40H</div>", "topic": "SIMPLE A. C. CIRCUITS : INDUCTOR - INDUCTIVE REACTANCE"}, {"id": "objective>Physics>2015>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What force has to be exerted on a mass 60kg to give it an acceleration of 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> vertically upwards.  <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">600N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1200N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">400N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">300N </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>  Mass, m = 60 kg  <br/>  Acceleration, a = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>  <br/>  Acceleration due to gravity, g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>  <br/>  The required force to move the body vertically upwards is W = m(g + a) <br/>  W = 60 (10 + 10) <br/> = 1,200N</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION~~MOTION: MOTION UNDER GRAVITY"}, {"id": "objective>Physics>2015>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A satellite revolving around the earth is kept on its orbit by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">centrifugal forces only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">centripetal forces only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">centripetal and frictional forces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">centripetal and centrifugal forces </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A satellite revolving around the earth is kept on its orbit by both centripetal and centrifugal forces. The centripetal force is the gravitational force that pulls the satellite towards the earth, keeping it in orbit. The centrifugal force is the apparent force that acts outward on a body moving around a center, arising from the body's inertia and counterbalances the centripetal force, keeping the satellite from falling into the earth.</div>", "topic": "GRAVITATIONAL FIELD : PARKING ORBIT AND WEIGHTLESSNESS"}, {"id": "objective>Physics>2015>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The plates of a 0.5µF unchanged capacitor are connected to a 10V battery. The charge on the capacitor after a long time is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20.0µC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50.0µC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0µC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0µC </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>  Capacitance, c = 0.5 µF  <br/>  Voltage, V = 10v  <br/>  Charge, Q = ?  <br/>  Recall that,  <br/>  Q = CV;  <br/>  Q = 10 × 0.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>C = 5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>  <br/>  = 5µC.</div>", "topic": "CAPACITORS"}, {"id": "objective>Physics>2015>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a document is to be produced using a duplicating camera, where should the document be placed in order to obtain an exact copy? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">At the point which is twice the focal length of the lens of the camera</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At the optical centre of the lens of the camera</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Between the principal focus and a point twice the focal length of the lens of the camera </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Beyond a point twice the focal length of the lens of the camera</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">* It should be noted the camera produces a real and inverted image on the film.  <br/>  * To produce a document that is the same as the exact copy. Then the magnification has to be unity; i,e it must be of a unit magnification.  <br/>  * To obtain a copy that is real, inverted and of unit magnification, the object (document) has to b placed at a point twice the focal point. That is µ = 2F</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2015>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The efficiency of a machine is 70%. Calculate the work done using this machine to raise a load 10kg through a vertical height of 2.0m. <br/>  <br/>  <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2000J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3000J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">286J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000J </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  Efficiency, E = 70%  <br/>  Work done by effort = ?  <br/>  Load(W) = 10kg × 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> = 100N  <br/>  Height (h) = 2m  <br/>  Recall that:  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">work done on load<hr size=\"1\" />workdone by effort</td></tr></table></div> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">70<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">load × distance moved by load<hr size=\"1\" />workdone by effort</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">70<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100 × 2<hr size=\"1\" />W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">E</span></td></tr></table></div> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">E</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100 × 2 × 100<hr size=\"1\" />70</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20000<hr size=\"1\" />70</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">285.71J</td></tr></table></div></div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2015>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statement is NOT true about atom? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An atom is made up of a nucleus and a number of electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mass of an atom is concentrated in the nucleus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Atoms of different elements have different atomic weights </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Atoms of all elements are identical </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">* Atoms of all elements are not identical.  <br/>  * Atoms of the same element are not always identical (isotopy)</div>", "topic": "ELEMENTARY MODERN PHYSICS : ELEMENTARY STRUCTURE OF THE ATOM"}, {"id": "objective>Physics>2015>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A current of 20A flows through a cable whose resistance is 5Ω. Calculate the electric power dissipated. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>W</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/> Current, I = 20A *l* Resistance, R = 5Ω, Power, P = ?  <br/> Recall that:  <br/>  P =I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R,  <br/>  P = (20)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × 5 = 2000W = 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>W</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2015>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From the diagram below, the equivalent capacitance of the three capacitor is <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1/3µF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/9µF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1µF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3µF</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2015/phy201511s.png\" style=\"position:relative;max-width:100%;\"/>  <br/>  - The capacitors are connected in series  <br/>  - For capacitors in series, the effective capacitance is given as   <br/>  1/C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> = 1/C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + 1/C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 1/C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + 1/C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> .... 1/C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />3</td></tr></table></div>  <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> = 1μF</div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>2015>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the temperature of 6 moles of an ideal gas at a pressure of 7.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> with a volume of 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  <br/> [R = 8.3Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">185<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">201<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">153<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">126<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>K</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>  Pressure, P = 7.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>  <br/>  Volume, v = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  Mole(n) = 6 mol  <br/> General Gas Constant, R = 8.3 Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  Recall that:  <br/>  PV = nRT  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">PV<hr size=\"1\" />nR</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">7.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span><hr size=\"1\" />6 x 8.3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">7.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><hr size=\"1\" />49.8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">152.6</td><td style=\"text-align:center;\">K</td></tr></table></div>  <br/>  ≈ 153K  <br/> </div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2015>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of cork floats in water because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the upthrust on it when completely immersed in water is greater than its weight in air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the surface of the water acts like an elastic skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the upthrust on it when completely immersed in water is equal to its weight in air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is no upthrust on it when it is completely immersed in water</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two forces acting on the cork when full immersed are its weight in air (downwards) and the upthrust (upwards). The cork floats because the upward force (upthrust) equals the downward force (its weight)  <br/>  That is; U = W <br/>  <br/> if upthrust were greater than its weight, the cork would accelerate upward (not just float).</div>", "topic": "LIQUIDS AT REST : LAW OF FLOATATION"}, {"id": "objective>Physics>2015>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A block of aluminium is heated electrically by a 25W heater. If the temperature rises by 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C in 5minutes. Calculate the heat capacity of the aluminium. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">750JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1250JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">125JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">50JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given <br/>  The mass of aluminium = m  <br/>  Power of the heater, P = 25W  <br/>  Temperature rise, Δθ = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C  <br/>  Tim, t = 5 minutes = 300s  <br/>  Recall:  <br/> Heat energy = Heat capacity &#215; Temperature difference <br/> i.e H = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>Δ&#952; <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">H<hr size=\"1\" />Δ&#952;</td></tr></table></div> <br/> H = Pt = 25 × 300 = 7500J  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">7500<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">750JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div></div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2015>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the diagram beside, the charges on X and Y are opposite. What happens when they are in contact?  <br/>  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X and Y become negatively charged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X and Y attract each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X and Y become positively charged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X an Y repel each other </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since they are oppositely charged, they attract each other when they are brought close to each other.</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>2015>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the speed of light in water is 2.26 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and the velocity of light in air is 3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Calculate the refractive index of water. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.33</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.23 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.45</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.56</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>  The speed of light in air = 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  The speed of light in water = 2.26 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  Recall that:  <br/>  Refractive index = velocity of light in vacuum / Velocity of light in medium  <br/>  * The medium in this case is water  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span><hr size=\"1\" />2.26×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />2.26</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.33</td></tr></table></div></div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2015>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Thermometer must be kept vertical  <br/>  <br/>  <br/> II. Top of the mercury meniscus is read <br/>  <br/>   <br/> III. Air use must be dry <br/>  <br/>  <br/> Which of the following precautions are common in verification of Boyle's law? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When verifying Boyle's law, it is important to take certain precautions to ensure accurate results. These precautions include: <br/>  <br/> Reading the top of the mercury meniscus: The top of the mercury meniscus is the highest point of the curved surface of the mercury in the thermometer. This is where the true reading should be taken. <br/>  <br/> Using dry air: The air in the apparatus should be dry to prevent any interference with the results. Moisture in the air can affect the volume of the gas being measured.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2015>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following does NOT use magnetic <br/> effect of current to function?  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A telephone receiver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead acid accumulator </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A moving coil galvanometer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">An electric bell </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A lead acid accumulator (or battery) does not use the magnetic effect of current to function. It operates on the principle of electrochemical reactions, where chemical energy is converted into electrical energy. The other options (telephone receiver, moving coil galvanometer, and electric bell) all use the magnetic effect of current in their operation.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2015>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What are the charge carriers in semiconductors? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Electrons and holes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Holes only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ion and electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ion and holes </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In semiconductors, both electrons and holes act as charge carriers. Electrons carry negative charge and move from the valence band to the conduction band, leaving behind 'holes' in the valence band. These holes act as positive charge carriers. Therefore, the correct answer is 'Electrons and holes'.</div>", "topic": "INTRODUCTORY ELECTRONICS"}, {"id": "objective>Physics>2015>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a capacitor is charged to 20C on each plate the energy stored by it is 40J, at what charges will it store half of this energy? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.0C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.4C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0C </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Given:</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">*</td><td style=\"text-align:center;\">The</td><td style=\"text-align:center;\">charge</td><td style=\"text-align:center;\">on</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">capacitor,</td><td style=\"text-align:center;\">Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20C</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">*</td><td style=\"text-align:center;\">Energy</td><td style=\"text-align:center;\">stored</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">capacity,</td><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40J</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Charge</td><td style=\"text-align:center;\">at</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">?</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">Q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />C</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />C</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">400<hr size=\"1\" />2C</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200<hr size=\"1\" />C</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">40C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200<hr size=\"1\" />40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5F</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">When</td><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20J</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">Q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />5</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />10</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">200</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">200&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">14.14C</td></tr></table></div></div>", "topic": "CAPACITORS : ENERGY STORED IN A CAPACITOR"}, {"id": "objective>Physics>2015>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the energy with which an incident light of wavelength 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> in falls on metal and electrons are emitted? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.99 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-18</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.99 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-16</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.99 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.99 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-20</span>J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>   <br/> Wave length λ = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>m  <br/>  Speed of light in vacuum, C = 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>  <br/>  Planck's constant, h = 6.63 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>  <br/>  Energy = ?  <br/>  Recall,  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">hc<hr size=\"1\" />λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.63×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>×3×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span><hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span></td></tr></table></div>  <br/>  E = 19.89 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>  <br/>  ≈ 1.99 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-18</span>J</div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2015>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will be applied when a metal Y is used to electroplate another metal X in electrolysis? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Y is the cathode and X is the anode </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y is the anode and very high current is used </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X is the anode and very high current is used </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X is the cathode and Y is the anode </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In electroplating, the metal to be plated (X) is made the cathode (negative electrode) and the metal to be used for plating (Y) is made the anode (positive electrode). The metal ions from the anode (Y) are oxidized and they move towards the cathode (X) where they are reduced and get deposited. Hence, 'X is the cathode and Y is the anode' is the correct answer.</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2015>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A progressive wave is represented by y = 10sin(1000πt - &#960;x/34). Two layers of the wave separated by 153cm have a phase different of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">270<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">360<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">810<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Given:</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10sin(</td><td style=\"text-align:center;\">1000πt</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">πx<hr size=\"1\" />34</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Comparing</td><td style=\"text-align:center;\">with</td><td style=\"text-align:center;\">y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Asin(</td><td style=\"text-align:center;\">2πftt</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">2πx<hr size=\"1\" />λ</td><td style=\"text-align:center;\">),</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Where</td><td style=\"text-align:center;\">Φ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2πx<hr size=\"1\" />λ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">So,</td><td style=\"text-align:center;\">2πx<hr size=\"1\" />λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">πx<hr size=\"1\" />34</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />34</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">68cm</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Φ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π × 153<hr size=\"1\" />68</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4.5π</td><td style=\"text-align:center;\">rad</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">Φ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">810<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">or</td><td style=\"text-align:center;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></td></tr></table></div></div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2015>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 100kg box is pushed along a road with a force of 500N. If the box moves with a uniform velocity, the coefficient of friction between the box and the road is  <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5 </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />R</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500<hr size=\"1\" />100×10</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500<hr size=\"1\" />1000</td></tr></table></div> <br/> U = 0.5</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2015>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From the generating station to each substation, power is transmitted at a very high voltage so as to reduce</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">eddy current loss </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hysteresis loss </div>", "<div style=\"font-family:Cambria;font-size:17px;\">heating in the coils </div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnetic flux leakage </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the generating station to each substation, power is transmitted at a very high voltage so as to reduce power loss because high current leads to energy waste in form of heat (resistive heating, H = i<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>Rt) <br/> </div>", "topic": "ELECTRICAL ENERGY AND POWER : ELECTRIC POWER TRANSMISSION"}, {"id": "objective>Physics>2015>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the velocity-time graphs shows uniform acceleration of the body from rest? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> - A velocity- time graph  <br/>  Recall that: V = U + at <br/>  Since the body is from rest, u = 0  <br/>  Re-write as V = at + u conforming the equation to  <br/>  y = mx + c  <br/>  v = at + u  <br/>  This is a linear graph</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2015>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An empty relative density bottle has a mass of 30g. When filled with paraffin, its mass is 70g. Calculate the mass of the bottle when it is filled with water <br/>  <br/>  <br/> [relative density of paraffin = 0.8]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">20g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">60g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">80g </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given <br/>  - Mass of bottle = 30g  <br/>  - Mass of bottle + Mass of paraffin = 70g  <br/>  - 30g + Mass of paraffin = 70g  <br/>  - Mass of paraffin = 70g - 30g = 40g  <br/>  - Relative density of parafin = 0.8  <br/>  Recall:  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Relative</td><td style=\"text-align:center;\">density</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">substance</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Mass of substance<hr size=\"1\" />mass of equal volume of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0.8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40<hr size=\"1\" />mass of water</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mass of water</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40<hr size=\"1\" />0.8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50g</td></tr></table></div> <br/> mass of bottle + water = 50 + 30 = 80g</div>", "topic": "LIQUIDS AT REST : RELATIVE DENSITY"}, {"id": "objective>Physics>2015>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A projectile is fired from the ground level with a velocity of 300ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> at an angle of 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span> to the horizontal. Calculate the time taken to reach the maximum height  <br/>  <br/>  <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">30s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">20s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">15s </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Velocity, U = 300 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  Angle, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>  <br/>  Time to teach maximum height, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> = ?  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">usinθ<hr size=\"1\" />g</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">300×sin30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span><hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15s</td></tr></table></div></div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>2015>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric bulb is labelled 260V, 80W. How much current is taken by the bulb? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.48A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.82A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.40A </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.31A </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Voltage, V = 260v  <br/>  Power, P = 80W  <br/> Current, I = ?  <br/>  Recall that:  <br/>  P = IV  <br/> 80 = I × 260  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80<hr size=\"1\" />260</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />13</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.31A</td></tr></table></div></div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2015>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A meter rule is pivoted at its mid-point with a vertical force of 10N hanging from the distance 30cm from the mid-point. At what distance must a 15N force hang to balance the ruler horizontally? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30cm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">20cm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10cm </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2015/phy201530s.png\" style=\"position:relative;max-width:100%;\"/>  <br/>  Given: <br/>  - The midpoint <br/> - The distance between the mid-point and a 10N force = 30cm  <br/>  - The distance between the midpoint and a 15N force on the other end to balance the metre rule horizontally = x  <br/>  Recall that,  <br/> - Net clockwise moment about a point is equal to the net anticlockwise moment about the same point.  <br/>  ∴ 10 × 30 = 15 × x  <br/>  300 = 15x  <br/>  x = 20cm.</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2015>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What type of reaction is represented by the equation below?  <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>X + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Y + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n + energy</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ionization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fission </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fusion </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>  <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>X + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Y + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n + energy <br/>  * The reaction above is nuclear fusion as simpler atoms are combined to form a larger one, a radiation and an energy release. </div>", "topic": "ELEMENTARY MODERN PHYSICS : FUSION AND FISSION"}, {"id": "objective>Physics>2015>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the period of vibration of a spring system of force constant 200Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> when loaded with a mass of 2kg. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.53s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.63s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.33s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.23s </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2⊼&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">&nbsp;</span></td><td style=\"text-align:center;\">m<hr size=\"1\" />k</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">3.143</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">&nbsp;</span></td><td style=\"text-align:center;\">2<hr size=\"1\" />200</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.286</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">&nbsp;</span></td><td style=\"text-align:center;\">1<hr size=\"1\" />100</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">6.286</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">1<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.63s</td></tr></table></div></div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2015>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From the diagram below, the measuring accuracy of the micrometer screw guage is  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.70mm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.78mm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.66mm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.16mm </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>  In the diagram,  <br/>  The main scale reading = 4.00mm   <br/> The micro reading = 0.16mm  <br/>  The micro metre screw gauge reading = 4.00 + 0.16 = 4.16mm</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2015>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The impulse of a force is deducted from Newton's second law as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">F = mg </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m(v - u)<hr size=\"1\" />t</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">F = ma </div>", "<div style=\"font-family:Cambria;font-size:17px;\">F = mv - mu </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Impulse = Force × time  <br/>  I = F &#215; t; I = Ft  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m(v-u)<hr size=\"1\" />t</td></tr></table></div> <br/> Ft = m(v - u)</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2015>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A charged particle is moving in a uniform magnetic field. If the direction of motion of the charged particle is parallel to the magnetic field, the path of the charged will </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">curve inwards </div>", "<div style=\"font-family:Cambria;font-size:17px;\">be a parabola </div>", "<div style=\"font-family:Cambria;font-size:17px;\">curve outwards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be a straight line </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a charged particles is moving in a uniform magnetic field and direction of the charge particles is parallel to that magnetic field , the path of the charged will be a straight lines  <br/> Since the magnetic force is perpendicular to the direction of travel, a charged ... velocity parallel to the field moves the particle along a straight line.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS : MAGNETIC FIELD ROUND A STRAIGHT CURRENT CARRYING CONDUCTOR, CIRCULAR WIRE AND SOLENOID"}, {"id": "objective>Physics>2015>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT affected by friction in machine? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Efficiency </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Effort </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Velocity ratio </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mechanical advantage </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Velocity ratio in a machine is independent of frictional force. It is only affected by the dimension, shape and size of the machine.</div>", "topic": "SIMPLE MACHINES"}, {"id": "objective>Physics>2015>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is both transverse and mechanical? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sound waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radio waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water waves </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X - rays </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Option A - Sound wave is longitudinal and mechanical  <br/> Option B - Radio wave is electromagnetic and transverse  <br/> Option C - Water wave is transverse and mechanical  <br/>  Option D - X-rays are transverse and electromagnetic</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2015>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a semiconducting material? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Copper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Silicon </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Steel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Iron</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Silicon is a semiconducting material. Semiconductors are materials which have a conductivity between conductors (generally metals) and nonconductors or insulators (such as most ceramics). Silicon is the most widely used semiconductor material because it can be used at much higher temperatures than germanium.</div>", "topic": "INTRODUCTORY ELECTRONICS"}, {"id": "objective>Physics>2015>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chemical energy is used to power which of the following? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Leclanche cell </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electric cell </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A dynamo </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Solar cell </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An electric cell uses chemical energy to produce electricity. The chemical reaction is a source of electrons that can be used to do work. The chemical reaction in an electric cell involves the transfer of electrons from one material (the anode) to another (the cathode).</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2015>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a primary and secondary colours are combined to produce white light, the phenomenon is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">complementary colours mixture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">subtractive mixtures of colours </div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary and primary colours mixture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary colours mixtures</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a primary and a secondary color are combined to produce white light, the phenomenon is known as complementary colors mixture. This is because the combination of a primary and a secondary color that are opposite each other on the color wheel will produce white light.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>2015>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/>  <br/> In the diagram above, at terminal velocity, the three forces are related by expression </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">v + u = mg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mg + v - u = 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">v - u = mg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mg + v = u </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At terminal velocity, the accelerating force equals zero. This means the some of the upward forces equals that of the downward force. <br/> ∴ v + u = mg</div>", "topic": "FRICTION : VISCOSITY AND TERMINAL VELOCITY"}, {"id": "objective>Physics>2015>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The different time rates of flow of fluid is due to  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cohesive force </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adhesive force </div>", "<div style=\"font-family:Cambria;font-size:17px;\">viscous force </div>", "<div style=\"font-family:Cambria;font-size:17px;\">surface tension </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The different time rates of flow of fluid is due to viscous force. Viscosity is a measure of a fluid's resistance to flow. It describes the internal friction of a moving fluid. A fluid with large viscosity resists motion because its molecular makeup gives it a lot of internal friction. A fluid with low viscosity flows easily because its molecular makeup results in very little friction when it is in motion.</div>", "topic": "FRICTION : VISCOSITY AND TERMINAL VELOCITY"}, {"id": "objective>Physics>2015>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a current of 4.6A was passed through a wire of resistance of 6.5Ω, the potential difference across the wire is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.4V </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.7V </div>", "<div style=\"font-family:Cambria;font-size:17px;\">29.9V </div>", "<div style=\"font-family:Cambria;font-size:17px;\">48.5V </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>  Current, I = 4.6A  <br/>  Resistance, R = 6.5Ω *nl Voltage, V = V  <br/>  Recall that  <br/>  V = IR  <br/>  V = 6.5 × 4.6 = 29.9V</div>", "topic": "CURRENT ELECTRICITY : OHM’S LAW"}, {"id": "objective>Physics>2015>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the diagram beside, the neutral point is at <br/>  <br/>   <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">S </div>", "<div style=\"font-family:Cambria;font-size:17px;\">R </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X </div>", "<div style=\"font-family:Cambria;font-size:17px;\">P </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">* The neutral point is at X.  <br/>  * At X, the magnetic fields completely neutralize each other.</div>", "topic": "MAGNETIC FIELD"}, {"id": "objective>Physics>2015>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following affects frictional force? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The relative velocity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The colour of the surface</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The area of contact of the given surfaces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The nature of the surfaces in contact.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Friction depends on the nature of the two surfaces. It depends on smoothness or roughness of the two surfaces which are in contact of each other. When two surfaces are in contact are smooth, then the friction between them is small because the interlocking of smooth surface is less.</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2015>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT an application of expansion in metals? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bimetallic strip thermometer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Temperature control in an electric iron </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Compensated balance wheel of watch </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sagging of telegraph wires </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sagging of telegraph wires is a consequence of thermal expansion, not an application of it. When metal wires are exposed to heat, they expand. This expansion can cause the wires to sag, which can be problematic for their functionality. </div>", "topic": "THERMAL EXPANSION : SOLIDS"}, {"id": "objective>Physics>2015>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Vapour is said to be saturated on top of an enclosed liquid if </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the rate of condensation is equal to that of vapourization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is neither condensation nor vapourization of the liquid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rate of condensation is less than that of vaporization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rate of condensation is greater than that of vaporization </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vapour is said to be saturated on top of an enclosed liquid if the rate of condensation is equal to that of vapourization. This means that the amount of liquid turning into vapour is the same as the amount of vapour turning back into liquid. This creates a balance, or equilibrium, where the amount of vapour in the air above the liquid remains constant.</div>", "topic": "VAPOURS : UNSATURATED AND SATURATED VAPOURS"}, {"id": "objective>Physics>2015>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body which weighs 50N in the air displaces 3.7kg of water when partially immersed in water. Calculate the upthrust on the body </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">37.0N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">87.0N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">13.0N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.7N </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  Weight in air, W = 50N  <br/>  Weight of water displaced, X = 3.7kg × 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> = 37N  <br/>  Upthrust, U = ?  <br/>  Recall that; Upthrust experienced by a body is equal to the weight of the fluid displaced. Hence the upthrust experienced is equal to 37N (weight of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O displaced) </div>", "topic": "LIQUIDS AT REST : UPTHRUST"}, {"id": "objective>Physics>2015>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the distance between the object and the pinhole camera is reduced by half, the size of the image of the object </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is doubled </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is quadrupled </div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains the same </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is halved </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall that:  <br/>  U α V where V is the size of the image and u is the size of the object  <br/>  U = KV  <br/>  U/V = K  <br/>  U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>  <br/>  U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/2  <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ?, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=</td><td style=\"text-align:center;\">U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div>;  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1/2U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2</td></tr></table></div>  <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> (The size is doubled) </div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2015>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A train with an initial velocity 20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> is subjected to uniform deceleration of 2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>. The time required to bring the train to a complete halt is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20S </div>", "<div style=\"font-family:Cambria;font-size:17px;\">40S </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10S </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5S </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  Initial Velocity, U = 20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  Acceleration = -2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> (since it's decelerating)  <br/>  Time, t = ? When V = 0  <br/>  Recall that:  <br/>  v = u + at  <br/>  0 = 20 - 2t  <br/>  t = 10s.</div>", "topic": "MOTION: LINEAR MOTION"}];
